solutionCodeJson.code:
WITH built AS (
    SELECT jsonb_agg(
             jsonb_build_object('id', id, 'name', name, 'price', (attrs ->> 'price')::int)
             ORDER BY id
           ) AS arr
    FROM   products
)
SELECT jsonb_array_length(arr) AS len,
       arr -> 0 ->> 'name'     AS first
FROM   built;

