solutionCodeJson.code:
CREATE INDEX IF NOT EXISTS idx_products_attrs ON products USING GIN (attrs);

SELECT
  (SELECT indexname FROM pg_indexes
   WHERE tablename = 'products' AND indexname = 'idx_products_attrs')  AS index,
  (SELECT count(*) FROM products WHERE attrs @> '{"brand":"Acme"}')    AS acme;

